let d;

if (typeof msg.payload === "string") {
    d = JSON.parse(msg.payload);
} else {
    d = msg.payload;
}

msg.payload = {
    weight_g: Number(d.weight_g),
    pct_drainage: Number(d.pct_drainage),
    ec_mscm: Number(d.ec_mscm),
    ph: Number(d.ph),
    input_mL: Number(d.input_mL),
    drainage_mL: Number(d.drainage_mL),
    water_used_mL: Number(d.water_used_mL),
    temp: Number(d.temp),
    soil_pct: Number(d.soil_pct),
    pump: d.pump === "ON" ? 1 : 0,
    drain_pump: d.drain_pump === "ON" ? 1 : 0
};

msg.measurement = "sensors";

return msg;

let d;
if (typeof msg.payload === 'string') {
    try {
        d = JSON.parse(msg.payload);
    } catch (e) {
        return null;
    }
} else {
    d = msg.payload;
}

flow.set('last_event', d);

const action = String(d.action || 'UNKNOWN');

msg.payload = {
    action: action,
    timestamp: d.timestamp || new Date().toISOString()
};

msg.measurement = "events";
msg.tags = {
    device: "abdellah",
    action: action
};

node.status({
    fill: "blue",
    shape: "dot",
    text: action
});

return msg;

let d;
if (typeof msg.payload === 'string') {
    try { d = JSON.parse(msg.payload); } catch(e) { return null; }
} else {
    d = msg.payload;
}

flow.set('last_timer', d);

msg.payload = {
    remaining_s: Number(d.remaining_s || 0),
    elapsed_s:   Number(d.elapsed_s   || 0),
    total_s:     Number(d.total_s     || 0),
    pct_done:    Number(d.pct_done    || 0),
    tour:        Number(d.tour        || 0),
    type_str:    String(d.type        || 'unknown')
};

msg.measurement = "timers";

msg.tags = {
    device: "abdellah",
    type:   String(d.type || 'unknown')
};

node.status({ fill: 'yellow', shape: 'dot',
    text: `${d.type} ${d.fmt} tour${d.tour}` });

return msg;

let d;
if (typeof msg.payload === 'string') {
    try { d = JSON.parse(msg.payload); } catch(e) { return null; }
} else { d = msg.payload; }

flow.set('rpi_status', d.status);

if (d.status === 'offline') {
    node.status({ fill:'red', shape:'dot', text:'RPi OFFLINE' });
} else {
    node.status({ fill:'green', shape:'dot', text:'RPi online' });
}
return msg;
